class DeepLinkValidationResult {
  final bool isValid;
  final String? errorMessage;
  final String? route;
  final String? subPath;
  final Map<String, String> queryParameters;

  const DeepLinkValidationResult({
    required this.isValid,
    this.errorMessage,
    this.route,
    this.subPath,
    this.queryParameters = const {},
  });

  factory DeepLinkValidationResult.invalid(String message) {
    return DeepLinkValidationResult(
      isValid: false,
      errorMessage: message,
    );
  }

  factory DeepLinkValidationResult.valid({
    required String route,
    String? subPath,
    Map<String, String> queryParameters = const {},
  }) {
    return DeepLinkValidationResult(
      isValid: true,
      route: route,
      subPath: subPath,
      queryParameters: queryParameters,
    );
  }
}

// ============================================================
// Deep Link Validator - Validates and sanitizes all parameters
// ============================================================

class DeepLinkValidator {
  /// Validates a deep link URI against the allowlist and security rules
  static DeepLinkValidationResult validate(Uri uri) {
    // 1. Validate scheme
    if (uri.scheme != DeepLinkConfig.scheme) {
      return DeepLinkValidationResult.invalid(
        'Invalid scheme: ${uri.scheme}. Expected: ${DeepLinkConfig.scheme}',
      );
    }

    // 2. Extract and validate the route (host in myapp://profile/123 format)
    final String route = uri.host.toLowerCase().trim();

    if (route.isEmpty) {
      return DeepLinkValidationResult.invalid('Empty route');
    }

    // 3. Check route against allowlist
    if (!DeepLinkConfig.allowedRoutes.contains(route)) {
      return DeepLinkValidationResult.invalid(
        'Route "$route" is not in the allowlist',
      );
    }

    // 4. Extract and validate sub-path
    String? subPath;
    final pathSegments = uri.pathSegments
        .where((s) => s.isNotEmpty)
        .toList();

    if (pathSegments.isNotEmpty) {
      subPath = pathSegments.first.trim();

      // Validate sub-path length
      if (subPath.length > DeepLinkConfig.maxParamLength) {
        return DeepLinkValidationResult.invalid(
          'Sub-path exceeds maximum length',
        );
      }

      // Validate sub-path characters (prevent injection)
      if (!DeepLinkConfig.validIdPattern.hasMatch(subPath)) {
        return DeepLinkValidationResult.invalid(
          'Sub-path contains invalid characters',
        );
      }

      // If the route has specific allowed sub-paths, validate against them
      final allowedSubs = DeepLinkConfig.allowedSubPaths[route];
      if (allowedSubs != null && allowedSubs.isNotEmpty) {
        if (!allowedSubs.contains(subPath.toLowerCase())) {
          return DeepLinkValidationResult.invalid(
            'Sub-path "$subPath" is not allowed for route "$route"',
          );
        }
      }
    }

    // 5. Validate query parameters
    final sanitizedParams = <String, String>{};
    for (final entry in uri.queryParameters.entries) {
      final key = entry.key.trim();
      final value = entry.value.trim();

      // Validate key length
      if (key.length > DeepLinkConfig.maxParamLength) {
        return DeepLinkValidationResult.invalid(
          'Query parameter key exceeds maximum length',
        );
      }

      // Validate value length
      if (value.length > DeepLinkConfig.maxParamLength) {
        return DeepLinkValidationResult.invalid(
          'Query parameter value exceeds maximum length',
        );
      }

      // Validate parameter characters
      if (!DeepLinkConfig.validParamPattern.hasMatch(key)) {
        return DeepLinkValidationResult.invalid(
          'Query parameter key contains invalid characters: "$key"',
        );
      }

      if (value.isNotEmpty && !DeepLinkConfig.validParamPattern.hasMatch(value)) {
        return DeepLinkValidationResult.invalid(
          'Query parameter value contains invalid characters for key "$key"',
        );
      }

      sanitizedParams[key] = value;
    }

    // 6. Check for path traversal attempts
    final fullPath = uri.toString();
    if (fullPath.contains('..') || fullPath.contains('%2e%2e') || fullPath.contains('%2E%2E')) {
      return DeepLinkValidationResult.invalid(
        'Path traversal attempt detected',
      );
    }

    return DeepLinkValidationResult.valid(
      route: route,
      subPath: subPath,
      queryParameters: sanitizedParams,
    );
  }

  /// Validates that an ID parameter is a valid numeric ID
  static bool isValidNumericId(String? id) {
    if (id == null || id.isEmpty) return false;
    final parsed = int.tryParse(id);
    return parsed != null && parsed > 0 && parsed < 2147483647;
  }

  /// Validates that an ID parameter is a valid UUID
  static bool isValidUuid(String? id) {
    if (id == null || id.isEmpty) return false;
    final uuidPattern = RegExp(
      r'^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$',
    );
    return uuidPattern.hasMatch(id);
  }
}

