class AuthService {
  static final AuthService _instance = AuthService._internal();
  factory AuthService() => _instance;
  AuthService._internal();

  bool _isAuthenticated = false;
  bool _isAdmin = false;
  String? _userId;

  bool get isAuthenticated => _isAuthenticated;
  bool get isAdmin => _isAdmin;
  String? get userId => _userId;

  /// Simulate login
  void login({required String userId, bool isAdmin = false}) {
    _isAuthenticated = true;
    _isAdmin = isAdmin;
    _userId = userId;
  }

  /// Simulate logout
  void logout() {
    _isAuthenticated = false;
    _isAdmin = false;
    _userId = null;
  }

  /// Check if user is authorized for a privileged route
  bool isAuthorizedForRoute(String route) {
    if (!_isAuthenticated) return false;

    if (route == 'admin' && !_isAdmin) return false;

    // Payment routes require authentication
    if (route == 'payment' && !_isAuthenticated) return false;

    // Settings routes require authentication
    if (route == 'settings' && !_isAuthenticated) return false;

    return true;
  }
}

