class DeepLinkHandler {
  static final DeepLinkHandler _instance = DeepLinkHandler._internal();
  factory DeepLinkHandler() => _instance;
  DeepLinkHandler._internal();

  StreamSubscription? _linkSubscription;
  final AuthService _authService = AuthService();

  // Pending deep link when user needs to authenticate first
  DeepLinkValidationResult? _pendingDeepLink;

  DeepLinkValidationResult? get pendingDeepLink => _pendingDeepLink;

  void clearPendingDeepLink() {
    _pendingDeepLink = null;
  }

  /// Initialize deep link handling
  Future<void> initialize(GlobalKey<NavigatorState> navigatorKey) async {
    // Handle initial deep link (app opened via deep link)
    try {
      final initialUri = await getInitialUri();
      if (initialUri != null) {
        _handleUri(initialUri, navigatorKey);
      }
    } catch (e) {
      debugPrint('DeepLinkHandler: Error getting initial URI: $e');
    }

    // Handle deep links while app is running
    _linkSubscription = uriLinkStream.listen(
      (Uri? uri) {
        if (uri != null) {
          _handleUri(uri, navigatorKey);
        }
      },
      onError: (Object err) {
        debugPrint('DeepLinkHandler: Error in URI stream: $err');
      },
    );
  }

  /// Dispose of the handler
  void dispose() {
    _linkSubscription?.cancel();
    _linkSubscription = null;
  }

  /// Handle an incoming URI with full validation
  void _handleUri(Uri uri, GlobalKey<NavigatorState> navigatorKey) {
    debugPrint('DeepLinkHandler: Received URI: $uri');

    // Step 1: Validate the deep link
    final validation = DeepLinkValidator.validate(uri);

    if (!validation.isValid) {
      debugPrint('DeepLinkHandler: Validation failed: ${validation.errorMessage}');
      _showError(navigatorKey, 'Invalid link: ${validation.errorMessage}');
      return;
    }

    final route = validation.route!;

    // Step 2: Check if route requires authorization
    if (DeepLinkConfig.privilegedRoutes.contains(route)) {
      if (!_authService.isAuthenticated) {
        debugPrint('DeepLinkHandler: User not authenticated for privileged route "$route"');
        // Store pending deep link and redirect to login
        _pendingDeepLink = validation;
        _navigateToLogin(navigatorKey);
        return;
      }

      if (!_authService.isAuthorizedForRoute(route)) {
        debugPrint('DeepLinkHandler: User not authorized for route "$route"');
        _showError(navigatorKey, 'You are not authorized to access this page.');
        return;
      }
    }

    // Step 3: Route to appropriate screen
    _navigateToRoute(navigatorKey, validation);
  }

  /// Navigate to the appropriate route based on validated deep link
  void _navigateToRoute(
    GlobalKey<NavigatorState> navigatorKey,
    DeepLinkValidationResult validation,
  ) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('DeepLinkHandler: Navigator not available');
      return;
    }

    final route = validation.route!;
    final subPath = validation.subPath;
    final params = validation.queryParameters;

    switch (route) {
      case 'profile':
        _handleProfileRoute(navigator, subPath, params);
        break;
      case 'payment':
        _handlePaymentRoute(navigator, subPath, params);
        break;
      case 'product':
        _handleProductRoute(navigator, subPath, params);
        break;
      case 'settings':
        _handleSettingsRoute(navigator, subPath, params);
        break;
      case 'home':
        navigator.pushNamedAndRemoveUntil('/home', (route) => false);
        break;
      default:
        debugPrint('DeepLinkHandler: Unhandled route "$route"');
        navigator.pushNamedAndRemoveUntil('/home', (route) => false);
    }
  }

  /// Handle profile deep links: myapp://profile/123
  void _handleProfileRoute(
    NavigatorState navigator,
    String? subPath,
    Map<String, String> params,
  ) {
    if (subPath == null) {
      // Navigate to own profile
      navigator.pushNamed('/profile');
      return;
    }

    // Validate profile ID is numeric
    if (!DeepLinkValidator.isValidNumericId(subPath)) {
      debugPrint('DeepLinkHandler: Invalid profile ID: $subPath');
      navigator.pushNamed('/error', arguments: 'Invalid profile ID');
      return;
    }

    navigator.pushNamed(
      '/profile',
      arguments: ProfileArguments(
        userId: subPath,
        source: params['source'] ?? 'deep_link',
        campaign: params['campaign'],
      ),
    );
  }

  /// Handle payment deep links: myapp://payment/confirm?order_id=abc123
  void _handlePaymentRoute(
    NavigatorState navigator,
    String? subPath,
    Map<String, String> params,
  ) {
    // Payment routes MUST have a sub-path
    if (subPath == null) {
      debugPrint('DeepLinkHandler: Payment route requires a sub-path');
      navigator.pushNamed('/error', arguments: 'Invalid payment link');
      return;
    }

    switch (subPath) {
      case 'confirm':
        final orderId = params['order_id'];
        if (orderId == null || orderId.isEmpty) {
          navigator.pushNamed('/error', arguments: 'Missing order ID');
          return;
        }
        // Additional validation: order ID format
        if (!DeepLinkConfig.validIdPattern.hasMatch(orderId)) {
          navigator.pushNamed('/error', arguments: 'Invalid order ID format');
          return;
        }
        navigator.pushNamed(
          '/payment/confirm',
          arguments: PaymentConfirmArguments(
            orderId: orderId,
            source: params['source'] ?? 'deep_link',
          ),
        );
        break;
      case 'status':
        final transactionId = params['transaction_id'];
        if (transactionId == null || transactionId.isEmpty) {
          navigator.pushNamed('/error', arguments: 'Missing transaction ID');
          return;
        }
        if (!DeepLinkConfig.validIdPattern.hasMatch(transactionId)) {
          navigator.pushNamed('/error', arguments: 'Invalid transaction ID');
          return;
        }
        navigator.pushNamed(
          '/payment/status',
          arguments: PaymentStatusArguments(transactionId: transactionId),
        );
        break;
      case 'receipt':
        final receiptId = params['receipt_id'];
        if (receiptId == null || receiptId.isEmpty) {
          navigator.pushNamed('/error', arguments: 'Missing receipt ID');
          return;
        }
        if (!DeepLinkConfig.validIdPattern.hasMatch(receiptId)) {
          navigator.pushNamed('/error', arguments: 'Invalid receipt ID');
          return;
        }
        navigator.pushNamed(
          '/payment/receipt',
          arguments: PaymentReceiptArguments(receiptId: receiptId),
        );
        break;
      default:
        navigator.pushNamed('/error', arguments: 'Unknown payment action');
    }
  }

  /// Handle product deep links: myapp://product/456
  void _handleProductRoute(
    NavigatorState navigator,
    String? subPath,
    Map<String, String> params,
  ) {
    if (subPath == null) {
      navigator.pushNamed('/products');
      return;
    }

    if (!DeepLinkValidator.isValidNumericId(subPath)) {
      debugPrint('DeepLinkHandler: Invalid product ID: $subPath');
      navigator.pushNamed('/error', arguments: 'Invalid product ID');
      return;
    }

    navigator.pushNamed(
      '/product',
      arguments: ProductArguments(
        productId: subPath,
        source: params['source'] ?? 'deep_link',
        campaign: params['campaign'],
        referrer: params['ref'],
      ),
    );
  }

  /// Handle settings deep links: myapp://settings/notifications
  void _handleSettingsRoute(
    NavigatorState navigator,
    String? subPath,
    Map<String, String> params,
  ) {
    if (subPath == null) {
      navigator.pushNamed('/settings');
      return;
    }

    navigator.pushNamed('/settings/$subPath');
  }

  /// Navigate to login screen
  void _navigateToLogin(GlobalKey<NavigatorState> navigatorKey) {
    navigatorKey.currentState?.pushNamed('/login');
  }

  /// Show error to user
  void _showError(GlobalKey<NavigatorState> navigatorKey, String message) {
    final navigator = navigatorKey.currentState;
    if (navigator != null) {
      navigator.pushNamed('/error', arguments: message);
    }
  }
}

